module top_module(
input clk,reset,
output reg [3:0] counter
    );  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)   
begin  
    if(reset)
        counter <= 4'b0000;
    else if(counter != 4'b1111)
        counter <= counter + 1;
    else
        counter <= 4'b0000;        
end    
endmodule
